What does this code output?

type Result<T, E> = { ok: true; value: T } | { ok: false; error: E };

function divide(a: number, b: number): Result<number, string> {
  if (b === 0) return { ok: false, error: 'Division by zero' };
  return { ok: true, value: a / b };
}

const r = divide(10, 0);
console.log(r.ok ? r.value : r.error);

What does this mapResult output?

function mapResult<T, U, E>(r: Result<T, E>, fn: (v: T) => U): Result<U, E> {
  if (r.ok) return { ok: true, value: fn(r.value) };
  return r;
}

const r: Result<number, string> = { ok: true, value: 5 };
const mapped = mapResult(r, x => x * 2);
console.log(mapped);

